import{_ as t,c as r,o,a2 as i}from"./chunks/framework.CIiVzG-O.js";const h=JSON.parse('{"title":"Customization","description":"","frontmatter":{},"headers":[],"relativePath":"guide/customize.md","filePath":"guide/customize.md","lastUpdated":1783607180000}'),n={name:"guide/customize.md"};function a(s,e,l,c,d,u){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="customization" tabindex="-1">Customization <a class="header-anchor" href="#customization" aria-label="Permalink to &quot;Customization&quot;">​</a></h1><p>Make NueZip truly yours by customizing your archive management experience. This guide covers everything you can personalize.</p><h2 id="general-preferences" tabindex="-1">General Preferences <a class="header-anchor" href="#general-preferences" aria-label="Permalink to &quot;General Preferences&quot;">​</a></h2><p>Open <strong>NueZip → Settings</strong> (or press <code>Cmd+,</code>) to access all customization options.</p><h3 id="appearance" tabindex="-1">Appearance <a class="header-anchor" href="#appearance" aria-label="Permalink to &quot;Appearance&quot;">​</a></h3><ul><li><strong>Theme</strong>: Choose between Light, Dark, or System (follows macOS appearance)</li><li><strong>Icon Style</strong>: Set monochrome or full-color menu bar icon</li><li><strong>Language</strong>: Select from supported languages (English, 中文, 日本語, 한국어, and more)</li></ul><h2 id="compression-defaults" tabindex="-1">Compression Defaults <a class="header-anchor" href="#compression-defaults" aria-label="Permalink to &quot;Compression Defaults&quot;">​</a></h2><p>Set your preferred compression defaults:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Options</th><th>Description</th></tr></thead><tbody><tr><td><strong>Default Format</strong></td><td>ZIP, 7z, TAR, GZIP, BZIP2, XZ</td><td>Archive format for quick compression</td></tr><tr><td><strong>Compression Level</strong></td><td>Store, Fast, Normal, Maximum, Ultra</td><td>Trade-off between speed and ratio</td></tr><tr><td><strong>Encryption</strong></td><td>None, AES-128, AES-256</td><td>Default encryption for ZIP/7z archives</td></tr><tr><td><strong>Volume Size</strong></td><td>Custom (MB)</td><td>Default split size for multi-volume archives</td></tr></tbody></table><h3 id="example-configuration" tabindex="-1">Example Configuration <a class="header-anchor" href="#example-configuration" aria-label="Permalink to &quot;Example Configuration&quot;">​</a></h3><p>For everyday use:</p><ul><li><strong>Format</strong>: ZIP</li><li><strong>Level</strong>: Normal</li><li><strong>Encryption</strong>: AES-256 (for sensitive files)</li><li><strong>Volume</strong>: Off</li></ul><p>For archiving:</p><ul><li><strong>Format</strong>: 7-Zip</li><li><strong>Level</strong>: Ultra</li><li><strong>Encryption</strong>: AES-256</li><li><strong>Volume</strong>: 4.7 GB (to fit on DVD)</li></ul><h2 id="extraction-preferences" tabindex="-1">Extraction Preferences <a class="header-anchor" href="#extraction-preferences" aria-label="Permalink to &quot;Extraction Preferences&quot;">​</a></h2><p>Customize extraction behavior:</p><ul><li><strong>Extract to subfolder by default</strong>: Auto-create a named folder when extracting</li><li><strong>Open folder after extraction</strong>: Reveal extracted contents in Finder</li><li><strong>Overwrite behavior</strong>: Ask, Always overwrite, or Skip existing files</li><li><strong>Preserve file dates</strong>: Keep original timestamps from the archive</li></ul><h2 id="finder-extension" tabindex="-1">Finder Extension <a class="header-anchor" href="#finder-extension" aria-label="Permalink to &quot;Finder Extension&quot;">​</a></h2><p>Manage the Finder context menu integration:</p><ul><li><strong>Enable/Disable</strong>: Turn right-click menu items on or off</li><li><strong>Quick actions</strong>: Choose which actions appear in the context menu <ul><li>Extract Here</li><li>Extract to Folder</li><li>Compress to ZIP</li><li>Compress with Options</li></ul></li></ul><p>Manage these in: <strong>System Settings → Privacy &amp; Security → Extensions → Finder Extensions</strong></p><h2 id="menu-bar-tray-icon" tabindex="-1">Menu Bar (Tray) Icon <a class="header-anchor" href="#menu-bar-tray-icon" aria-label="Permalink to &quot;Menu Bar (Tray) Icon&quot;">​</a></h2><p>Customize the menu bar drop panel:</p><ul><li><strong>Show in menu bar</strong>: Enable/disable the tray icon</li><li><strong>Auto-close panel</strong>: Close drop panel after extraction</li><li><strong>Recent archives</strong>: Number of recent items to show</li><li><strong>Quit on close</strong>: Whether the app stays in the background</li></ul><h2 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h2><ul><li><strong>Show completion alerts</strong>: Notify when long operations finish</li><li><strong>Show error alerts</strong>: Display notifications for failed operations</li><li><strong>Sound</strong>: Play a sound when operations complete</li></ul><h2 id="general-settings" tabindex="-1">General Settings <a class="header-anchor" href="#general-settings" aria-label="Permalink to &quot;General Settings&quot;">​</a></h2><p>Access these in <strong>Settings → General</strong>:</p><ul><li><strong>Language</strong>: Switch between English and Chinese (Simplified)</li><li><strong>Launch at Login</strong>: PetReminder starts automatically when you log in</li><li><strong>Theme</strong>: Light or dark mode (follows system by default)</li><li><strong>Menu bar icon</strong>: Show or hide the menu bar icon</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Assign different pets to different types of reminders for variety</li><li>Reduce animation speed if the pet is too distracting</li><li>Try pairing a calm pet (Ragdoll) for work reminders and an energetic one (Shiba) for breaks</li><li>Enable &quot;Launch at Login&quot; so you never miss important reminders</li></ul>',31)])])}const p=t(n,[["render",a]]);export{h as __pageData,p as default};
